Given an integer representing a BrickLink color number, write a function `bricklinkColorToLEGO :: Int -> ColorInfo` that returns a record containing the LEGO equivalent of that color number if it exists. The record should have the following fields: `name` (a String representing the color name), `lego` (the LEGO color number), and `brickLink` (the BrickLink color number). If the color number is negative or does not exist in the predefined color map, return a record with `name` set to "Unknown", `lego` set to the input color number, and `brickLink` set to the input color number. The predefined color map is:

    1: {name = "Red",   lego = 1, brickLink = 1}
    2: {name = "Blue",  lego = 2, brickLink = 2}
    3: {name = "Green", lego = 3, brickLink = 3}

import Data.List (permutations, sort, nub)

generateAnagrams :: String -> [String]
generateAnagrams s = sort . nub $ permutations s

import Data.List (sortBy)
import Data.Ord (comparing)
import Data.Char (isDigit)

sortMemories :: [String] -> [String]
sortMemories = sortBy (comparing getYear)
  where
    getYear :: String -> Int
    getYear str = read $ takeWhile isDigit str

import Data.Char (isAlphaNum, toUpper)

standardizeProductCodes :: [String] -> [String]
standardizeProductCodes inputCodes = [map toUpper [c | c <- code, isAlphaNum c] | code <- inputCodes]

import Data.List (sortBy)
import Data.Function (on)
import Data.List.Split (splitOn)

getPrepTime :: String -> Int
getPrepTime s = read (splitOn "," s !! 1)

sortRecipes :: [String] -> [String]
sortRecipes = sortBy (compare `on` getPrepTime)

import Data.List (sortBy)
import Data.Ord (comparing)

reverseAlphaSort :: [String] -> [String]
reverseAlphaSort = sortBy (flip compare)

data Match = Match { matchId :: Int, goals :: Int }

calculateTotalGoals :: [Match] -> Int
calculateTotalGoals matches = sum $ map goals matches

import Data.Bits (popCount)
import Data.List (sortBy)
import Data.Ord (comparing)

sortByBinaryOnes :: [Int] -> [Int]
sortByBinaryOnes arr = sortBy comparePop arr
  where
    comparePop x y =
      let countX = popCount x
          countY = popCount y
      in compare countX countY <> compare y x

{-# LANGUAGE CPP #-}
import System.Posix.Signals (installHandler, Handler(Catch), sigINT, sigPIPE)
import Control.Exception (SomeException, catch)

registerSignalHandlers :: IO () -> IO ()
registerSignalHandlers handlerFunction = do
  -- Register handler for SIGINT (always available)
  _ <- installHandler sigINT (Catch handlerFunction) Nothing
#ifdef HAS_SIGPIPE
  -- Register handler for SIGPIPE when supported by the platform
  catch (installHandler sigPIPE (Catch handlerFunction) Nothing >> return ())
        (\(_ :: SomeException) -> return ())
#else
  -- If SIGPIPE is not defined, skip
  return ()
#endif
  return ()
